public int canCompleteCircuit(int[] gas, int[] cost) {
    int totalGas = 0;
    int totalCost = 0;
    int fuel = 0;
    int start = 0;

    for(int i = 0; i < gas.length; i++){
        totalGas += gas[i];
        totalCost += cost[i];
        fuel += gas[i] - cost[i];

        if(fuel < 0){
            start = i + 1;
            fuel = 0;
        }
    }

    return totalGas >= totalCost ? start : -1;
}

