def canCompleteCircuit(gas, cost):
    totalGas = sum(gas)
    totalCost = sum(cost)

    if totalGas < totalCost:
        return -1

    fuel = 0
    start = 0

    for i in range(len(gas)):
        fuel += gas[i] - cost[i]

        if fuel < 0:
            start = i + 1
            fuel = 0

    return start

